sql:
SELECT model_id 
FROM model_teams 
WHERE access_level = 'read-only';

SELECT model_id 
FROM models 
WHERE model_id NOT IN (SELECT model_id FROM model_access_logs);

SELECT model_id, f1_score
FROM evaluation_metrics
WHERE f1_score = (
    SELECT MAX(f1_score)
    FROM evaluation_metrics
);

external_knowledge:
- 'freely shared' refers to models that have 'public' visibility in the database;
- 'less than a thousand labels' is a metaphorical way of saying the number of labels is less than 1000;
- 'exceptionally precise' translates to models that have an average accuracy greater than 0.9;
- 'where these treasures lie' is a metaphor for the file paths of the models in the repository.

sql:
SELECT * FROM models
WHERE model_id IN (SELECT model_id FROM model_versions)
AND model_id NOT IN (SELECT model_id FROM model_teams);

SELECT COUNT(DISTINCT user_id) AS download_user_count
FROM model_access_logs
WHERE access_type = 'download';

SELECT description
FROM models
WHERE num_train_samples > (SELECT AVG(num_train_samples) * 2 FROM models);

SELECT cm.model_id, cm.cov_at_1, cm.cov_at_2, cm.cov_at_3, cm.precision, cm.recall, cm.f1_score
FROM coverage_metrics cm
WHERE cm.model_id = 0;

external_knowledge:
- "top-notch models" refers to models with higher accuracy than the average model; 
- "usual training datasets" refers to the average number of training samples used across all training datasets; 
- "better accuracy rate than the general average" means the model's average accuracy is above the average accuracy of all models.

- "gardeners" refers to researchers;
- "blossoms" refers to models;
- "golden standard of 90% perfection" refers to an accuracy level of 0.9.

sql:
SELECT model_id, f1_score
FROM evaluation_metrics
WHERE f1_score = (SELECT MAX(f1_score) FROM evaluation_metrics);

SELECT models.model_id, coverage_metrics.f1_score
FROM models
JOIN coverage_metrics ON models.model_id = coverage_metrics.model_id;

SELECT mv.version_id, mv.model_id
FROM model_versions mv
WHERE strftime('%m', mv.updated_at) IN ('04', '05');
